use keccak256::keccak256;

// keccak256("EIP712Domain(string name,string version,uint256 chainId,address verifyingContract)")
pub global TYPE_HASH: [u8; 32] = [139, 115, 195, 198, 155, 184, 254, 61, 81, 46, 204, 76, 247, 89, 204, 121, 35, 159, 123, 23, 155, 15, 250, 202, 169, 167, 93, 82, 43, 57, 64, 15];

pub fn build_domain_separator<let N: u32, let V: u32>(name: [u8; N], version: [u8; V], chain_id: Field, verifying_contract: Field) -> [u8; 32] {
    let name_hash = keccak256(name, N);
    let version_hash = keccak256(version, V);
    let chain_id_bytes: [u8; 32] = chain_id.to_be_bytes();
    let verifying_contract_bytes: [u8; 32] = verifying_contract.to_be_bytes();

    // Concatenate all bytes into a single array
    let mut full_bytes: [u8; 160] = [0; 160];
    for i in 0..32 {
        full_bytes[i] = TYPE_HASH[i];
        full_bytes[32 + i] = name_hash[i];
        full_bytes[64 + i] = version_hash[i];
        full_bytes[96 + i] = chain_id_bytes[i];
        full_bytes[128 + i] = verifying_contract_bytes[i];
    }

    let domain_separator = keccak256(full_bytes, 160);
    domain_separator
}

pub fn to_struct_hash<let N: u32>(primary_type_hash: [u8; 32], message: [u8; N]) -> [u8; 32] {
    let mut full_bytes: [u8; N + 32] = [0; N + 32];
    for i in 0..32 {
        full_bytes[i] = primary_type_hash[i];
    }
    for i in 0..N {
        full_bytes[32 + i] = message[i];
    }
    let struct_hash = keccak256(full_bytes, N + 32);
    struct_hash
}

pub fn hash_typed_data_v4(domain_separator: [u8; 32], struct_hash: [u8; 32]) -> [u8; 32] {
    let mut full_bytes: [u8; 66] = [0; 66];
    full_bytes[0] = 0x19;
    full_bytes[1] = 0x01;
    for i in 0..32 {
        full_bytes[2 + i] = domain_separator[i];
        full_bytes[34 + i] = struct_hash[i];
    }
    let typed_data_hash = keccak256(full_bytes, 66);
    typed_data_hash
}

#[test]
fn test_eip712_mail() {
    // Replicates the EIP-712 example from index.ts:
    //   domain: { name: "EIP712", version: "1", chainId: 1, verifyingContract: 0x0 }
    //   primaryType: "Mail"
    //   Mail { from: Person("John Doe", 0x0), to: Person("Jane Doe", 0x0), contents: "Hello, world!" }

    // keccak256("Person(string name,address wallet)")
    let person_type_hash: [u8; 32] = [185, 216, 199, 138, 207, 155, 152, 115, 17, 222, 108, 123, 69, 187, 106, 156, 142, 27, 243, 97, 250, 127, 211, 70, 122, 33, 99, 249, 148, 199, 149, 0];
    // keccak256("Mail(Person from,Person to,string contents)Person(string name,address wallet)")
    let mail_type_hash: [u8; 32] = [160, 206, 222, 178, 220, 40, 11, 163, 155, 133, 117, 70, 215, 79, 85, 73, 195, 161, 215, 189, 194, 221, 150, 191, 136, 31, 118, 16, 142, 35, 218, 194];

    let john_doe_hash: [u8; 32] = keccak256("John Doe".as_bytes(), 8);
    let jane_doe_hash: [u8; 32] = keccak256("Jane Doe".as_bytes(), 8);
    let contents_hash: [u8; 32] = keccak256("Hello, world!".as_bytes(), 13);

    let zero_addr: [u8; 32] = [0; 32];

    // Encode and hash Person("John Doe", 0x0)
    // = keccak256(personTypeHash || keccak256("John Doe") || padded_address)
    let mut from_encoded: [u8; 96] = [0; 96];
    for i in 0..32 {
        from_encoded[i] = person_type_hash[i];
        from_encoded[32 + i] = john_doe_hash[i];
        from_encoded[64 + i] = zero_addr[i];
    }
    let from_person_hash: [u8; 32] = keccak256(from_encoded, 96);

    // Encode and hash Person("Jane Doe", 0x0)
    let mut to_encoded: [u8; 96] = [0; 96];
    for i in 0..32 {
        to_encoded[i] = person_type_hash[i];
        to_encoded[32 + i] = jane_doe_hash[i];
        to_encoded[64 + i] = zero_addr[i];
    }
    let to_person_hash: [u8; 32] = keccak256(to_encoded, 96);

    // Mail message = fromPersonHash || toPersonHash || contentsHash (96 bytes)
    let mut message: [u8; 96] = [0; 96];
    for i in 0..32 {
        message[i] = from_person_hash[i];
        message[32 + i] = to_person_hash[i];
        message[64 + i] = contents_hash[i];
    }

    let struct_hash = to_struct_hash(mail_type_hash, message);
    let expected_struct_hash: [u8; 32] = [62, 220, 201, 133, 236, 4, 33, 175, 209, 125, 28, 179, 187, 13, 251, 45, 234, 18, 235, 187, 251, 0, 28, 248, 112, 14, 240, 178, 208, 128, 194, 28];
    assert(struct_hash == expected_struct_hash, "struct hash mismatch");

    // Domain: name="EIP712", version="1", chainId=1, verifyingContract=0x0
    let domain_separator = build_domain_separator(
        "EIP712".as_bytes(),
        "1".as_bytes(),
        1,
        0,
    );

    let typed_data_hash = hash_typed_data_v4(domain_separator, struct_hash);
    let expected_message_hash: [u8; 32] = [148, 130, 35, 222, 246, 39, 216, 25, 20, 10, 49, 97, 134, 204, 141, 234, 252, 43, 153, 234, 103, 114, 162, 99, 233, 170, 214, 29, 131, 115, 164, 136];
    assert(typed_data_hash == expected_message_hash, "typed data hash mismatch");
}

